# scripts/check_parity.py
import hashlib, json, os, sys
import boto3, requests, yaml

def sha256_dir(path: str) -> str:
    """Stable hash of all files under path (sorted by filename)."""
    h = hashlib.sha256()
    for root, dirs, files in os.walk(path):
        dirs.sort()
        for name in sorted(files):
            with open(os.path.join(root, name), "rb") as f:
                h.update(f.read())
    return h.hexdigest()

def get_running_image_digest(env: str) -> str:
    """Read the digest label from the running pod via the version endpoint."""
    url = os.environ[f"{env.upper()}_VERSION_URL"]
    resp = requests.get(url, timeout=10)
    resp.raise_for_status()
    return resp.json()["image_digest"]

def check_parity(config_path: str = "parity_config.yaml") -> list[dict]:
    with open(config_path) as f:
        config = yaml.safe_load(f)

    allowed_diffs = {d["dimension"] for d in config["parity"]["documented_differences"]}
    violations = []

    # Check container image digest
    digests = {env: get_running_image_digest(env) for env in ["dev", "staging", "prod"]}
    if len(set(digests.values())) > 1:
        violations.append({
            "dimension": "container_image_digest",
            "values": digests,
            "blocking": True,
        })

    # Check prompt hash (prompts/ dir in the repo, compared to what's baked in each env)
    prompt_hash = sha256_dir("prompts/")
    for env in ["dev", "staging", "prod"]:
        url = os.environ[f"{env.upper()}_VERSION_URL"]
        env_hash = requests.get(url, timeout=10).json()["prompt_sha256"]
        if env_hash != prompt_hash:
            violations.append({
                "dimension": "prompt_file_sha256",
                "env": env,
                "expected": prompt_hash,
                "actual": env_hash,
                "blocking": True,
            })

    # Check model API version
    api_versions = {}
    for env in ["dev", "staging", "prod"]:
        url = os.environ[f"{env.upper()}_VERSION_URL"]
        api_versions[env] = requests.get(url, timeout=10).json()["model_api_version"]
    if len(set(api_versions.values())) > 1:
        violations.append({
            "dimension": "model_api_version",
            "values": api_versions,
            "blocking": "model_api_version" not in allowed_diffs,
        })

    blocking = [v for v in violations if v.get("blocking")]
    if blocking:
        print("PARITY VIOLATIONS (blocking):")
        for v in blocking:
            print(f"  {v['dimension']}: {v}")
        sys.exit(1)

    print(f"Parity OK. {len(violations)} documented differences.")
    return violations

if __name__ == "__main__":
    check_parity()

