import hashlib, json, os, pathlib

def compute_prompt_sha256(prompt_dir: str = "/app/prompts") -> str:
    h = hashlib.sha256()
    for p in sorted(pathlib.Path(prompt_dir).rglob("*")):
        if p.is_file():
            h.update(p.read_bytes())
    return h.hexdigest()

def version_info() -> dict:
    """Return the version envelope baked into this container."""
    return {
        "image_digest": os.environ.get("IMAGE_DIGEST", "unknown"),
        "prompt_sha256": compute_prompt_sha256(),
        "model_api_version": os.environ.get("MODEL_API_VERSION", "unknown"),
        "app_version": os.environ.get("APP_VERSION", "unknown"),
        "environment": os.environ.get("DEPLOY_ENV", "unknown"),
        "built_at": os.environ.get("BUILD_TIMESTAMP", "unknown"),
    }

